import React from "react";
import "./jobLists.css"
import ApiRequest from "../../../Services/ApiRequest";
import MenteeJobLists from "../../JobPosting/Components/MenteeJobLists";
import HeaderMenteeDashboard from "../../../Components/Layouts/DashboardLayout/MenteeLayout/HeaderMenteeDashboard";
import MenteeSidebar from "../../../Components/Layouts/DashboardLayout/MenteeLayout/MenteeSidebar";
import { Link } from "react-router-dom";
import PostIcon from "../../../assets/images/DashboardImgs/post-icon.png";
import Search from "../../../assets/images/DashboardImgs/search.png";
import { X } from "react-bootstrap-icons";


class JobsList extends React.Component {
    state = {
        jobLists: [],
        active: false,
        featured: false,
        sort: '',
        searchInput: false,
        appliedJobs:[]
    }
    componentDidMount() {
        this.getAllJobs();
        this.getAppliedJobs();
        
    }

    getAllJobs = async() =>{
        
        const getJobs = await ApiRequest.getRequest('/getAllJobs');
        console.log(getJobs);
        if (getJobs && getJobs.status === 200) {
            this.setState({
                jobLists: getJobs.data.jobLists,
                postCount: getJobs.data.jobLists.data.length
            })
        }
    }

    getAppliedJobs = async() =>{
        const response = await ApiRequest.getRequest('/getAppliedJobs');
        console.log(response)
        if(response && response.status === 200){
            this.setState({
                appliedJobs:response.data.applied
            })
        }
    }
    searchForm = (event) => {
        event.preventDefault();
        this.filterJobByStatus();
    }
    onChangeFilterVal = (event) => {
        const { name, value } = event.target;
        this.setState({
            [name]: value
        }, () => {
            this.filterJobByStatus();
        })
    }
    onChangeJobStatus = (val) => {
        const btn = ['active', 'featured']
        this.setState({
            [val]: !this.state[val]
        })
        btn.map((key) => {
            if (key !== val) {
                this.setState({
                    [key]: false
                }, () => {
                    this.filterJobByStatus();
                })
            }
        })

    }
    filterJobByStatus = async () => {
        const { active, inActive, featured, sort, search } = this.state;
        const response = await ApiRequest.postRequest('/postSearchMentee', { active, inActive, featured, sort, search })
        if (response && response.status === 200) {
            this.setState({
                jobLists: response.data.jobLists,
                postCount: response.data.jobLists.data.length
            })
        }
    }
    clearFilter = () => {
        this.setState({
            active: '',
            inActive: '',
            featured: '',
            sort: '',
            search: '',
        }, () => this.filterJobByStatus())
    }
    jobApplied = async(val) =>{
        const response = await ApiRequest.postRequest('/jobApplied', { post_id:val })
        console.log(response);
        if (response && response.status === 200) {
            this.getAppliedJobs()
        }
    }
    render() {
        return (
            <div className="container-fluid dashboard-body-bg p-0">
                <div className='dashboard'>
                    <MenteeSidebar />
                    <div className='dashboard-app'>
                        <HeaderMenteeDashboard />
                        <div className='container-fluid ProfileWrap'>
                            <div className="row mar-width-0 jobPostingFilterWrap">
                                <div className="row mar-width-0 jobPostingFilterWrapInner1">

                                    <div className="row mar-width-0 p-0 border-bottom pt-2 pb-2">
                                        <div className="col-md-6">
                                            <li className={`nav-item dropdown user-dropdown d-inline-block ${this.state.active || this.state.featured ? 'st-active' : ''}`}>
                                                <Link to="#" className="nav-link dropdown-toggle"
                                                    id="navbarDropdownMenuLink" role="button" data-bs-toggle="dropdown"
                                                    aria-expanded="false">
                                                    Active and Featured jobs
                                                </Link>
                                                <ul className="dropdown-menu shadow-sm"
                                                    aria-labelledby="navbarDropdownMenuLink">
                                                    <li><Link to="#" className={`dropdown-item ${this.state.active ? 'active' : ''}`} onClick={() => this.onChangeJobStatus('active')} >Active</Link></li>
                                                    <li><Link to="#" className={`dropdown-item ${this.state.featured ? 'active' : ''}`} onClick={() => this.onChangeJobStatus('featured')} >Featured</Link></li>
                                                </ul>
                                            </li>
                                        </div>
                                        <div className="col-md-3 text-right">
                                            <button className="btn btn-post" onClick={() => { this.clearFilter() }}>Clear filter</button>
                                        </div>
                                        <div className="col-md-3">
                                            <select className="form-select" aria-label="Default select example" onChange={this.onChangeFilterVal} name="sort" value={this.state.sort}>
                                                <option selected>Sort by: All Jobs</option>
                                                <option value="ASC">ASC</option>
                                                <option value="DESC">DESC</option>
                                            </select>
                                        </div>
                                    </div>

                                    <div className="row mar-width-0 p-0 pt-2 pb-2 filter-2">
                                        <div className="col-md-12 text-right search">
                                            <form onSubmit={this.searchForm} className="searchForm">
                                                <div className="form-group text-left position-relative">
                                                    <input type="search" className="form-control searchInput" onChange={this.onChangeFilterVal} name="search" value={this.state.search} placeholder="search.... " />
                                                </div>
                                            </form>
                                        </div>
                                    </div>
                                </div>
                                <MenteeJobLists className="row mar-width-0 dashboardSectionTwo p-0" appliedJobs={this.state.appliedJobs} jobLists={this.state.jobLists} pagination={true} checkBox={false} jobApplied={this.jobApplied} />
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        )
    }
}

export default JobsList;